dados = d3.csv("https://docs.google.com/spreadsheets/d/e/2PACX-1vR_kABBziuLQDcgkwtThORXGuhxlp9G1mWXsb9Xv6XzB9T4K47YFWr6oRXahriBjqsIeQgl1pe_stIe/pub?gid=0&single=true&output=csv")

// 3. Filtra estaticamente apenas as demandas do Protótipo
demandas_proto = dados.filter(d =&gt; d.Categoria === "Protótipo")

// 4. Cria os componentes visuais de filtro
viewof filtro_setor = Inputs.select(["Todos", ...new Set(demandas_proto.map(d =&gt; d.Setor))], {label: "Filtrar por Setor:"})
viewof filtro_status = Inputs.select(["Todos", ...new Set(demandas_proto.map(d =&gt; d.Status))], {label: "Filtrar por Status:"})

// 5. Aplica os filtros dinâmicos baseados na seleção do usuário
tarefas_filtradas = demandas_proto.filter(d =&gt; 
  (filtro_setor === "Todos" || d.Setor ===  filtro_setor) &&
  (filtro_status === "Todos" || d.Status === filtro_status)
)

// Helper function para calcular a diferença de dias
function calcularDiasRestantes(prazoStr) {
  if (!prazoStr || prazoStr.trim() === "") return null;

  // Trata formatos comuns de data (AAAA-MM-DD ou DD/MM)
  const partes = prazoStr.split(/[-/]/);
  let dataPrazo;

  if (partes.length === 3) {
    dataPrazo = new Date(partes[0], partes[1] - 1, partes[2]);
  } else if (partes.length === 2) {
    dataPrazo = new Date(new Date().getFullYear(), partes[1] - 1, partes[0]);
  } else {
    dataPrazo = new Date(prazoStr);
  }

  const hoje = new Date();
  hoje.setHours(0,0,0,0);
  dataPrazo.setHours(0,0,0,0);

  const diffTempo = dataPrazo - hoje;
  return Math.ceil(diffTempo / (1000 * 60 * 60 * 24));
}












































// 6. Renderiza os blocos expansíveis (accordion nativo HTML)
html`${tarefas_filtradas.map(d =&gt; {
  const dias = d.Prazo ? calcularDiasRestantes(d.Prazo) : null;
  let prazoTexto = "Sem prazo definido";
  let badgeCor = "#6c757d"; // Cinza padrão

  if (dias !== null) {
    if (dias &lt; 0) {
      prazoTexto = `Atrasada há ${Math.abs(dias)} dias`;
      badgeCor = "#dc3545"; // Vermelho
    } else if (dias === 0) {
      prazoTexto = "Entrega HOJE";
      badgeCor = "#fd7e14"; // Laranja
    } else {
      prazoTexto = `${dias} dias restantes`;
      badgeCor = dias &lt;= 3 ? "#ffc107" : "#198754"; // Amarelo se perto, senão Verde
    }
  }

  return `
    &lt;details style="background: #1a1a1a; border: 1px solid #333; padding: 12px; margin-bottom: 10px; border-radius: 6px;"&gt;
      &lt;summary style="cursor: pointer; font-weight: bold; font-size: 1.1em; display: flex; justify-content: space-between; align-items: center;"&gt;
        &lt;div&gt;
          &lt;span style="color: #0dfd9e; margin-right: 8px;"&gt;[${d.Setor}]&lt;/span&gt;
          &lt;span&gt;${d.Tarefa}&lt;/span&gt;
        &lt;/div&gt;
        &lt;div style="display: flex; gap: 8px;"&gt;
          &lt;span style="background: #333; color: #fff; padding: 2px 8px; border-radius: 4px; font-size: 0.8em;"&gt;${d.Status}&lt;/span&gt;
          &lt;span style="background: ${badgeCor}; color: #fff; padding: 2px 8px; border-radius: 4px; font-size: 0.8em;"&gt;${prazoTexto}&lt;/span&gt;
        &lt;/div&gt;
      &lt;/summary&gt;
      &lt;div style="margin-top: 12px; padding-top: 12px; border-top: 1px solid #333; color: #ccc; line-height: 1.5;"&gt;
        &lt;p&gt;&lt;strong&gt;Descrição:&lt;/strong&gt; ${d.Descrição || "Nenhuma descrição fornecida."}&lt;/p&gt;
        &lt;p&gt;&lt;strong&gt;Responsável:&lt;/strong&gt; ${d.Responsável || "Não atribuído."}&lt;/p&gt;
        &lt;p&gt;&lt;strong&gt;Prazo Final:&lt;/strong&gt; ${d.Prazo || "Não estipulado."}&lt;/p&gt;
      &lt;/div&gt;
    &lt;/details&gt;
  `;
}).join('')}`
